def clean_source(source):
    if pd.isna(source):
        return "Unknown"

    # 1. Lowercase and remove tracking parameters (anything after & or ?)
    source = str(source).lower().split('&')[0].split('?')[0]

    # 2. Group the "Big Three" Ecosystems
    if any(x in source for x in ['facebook', 'fb', 'meta']):
        return 'Facebook'
    if 'google' in source or 'goog' in source:
        return 'Google'
    if 'instagram' in source or 'ig' in source:
        return 'Instagram'
    if 'linkedin' in source:
        return 'LinkedIn'
    if 'youtube' in source:
        return 'YouTube'
    if 'linktree' in source or 'linktr.ee' in source:
        return 'Linktree'
    if 'twitter' in source or 't.co' in source or 'threads' in source:
        return 'X / Threads'
    if any(x in source for x in ['sms', 'text']):
        return 'SMS'
    if any(x in source for x in ['edm', 'email', 'outlook', 'newsletter']):
        return 'Email'
    if 'unicef' in source:
        return 'Internal / Unicef'

    if 'au.search.yahoo' in source or 'yahoo' in source:
        return 'Yahoo'

    if 'qantas' in source or 'qantas.com' in source:
        return 'Qantas'

    # 3. Clean up Domain remainders (e.g., yahoo.com.au -> yahoo)
    source = source.replace('.com', '').replace('.au', '').replace('.org', '').replace('.net', '')

    return source.strip()

